#nullable enable // autogenerated

using System.Xml;
using MVZ2.IO;

namespace MVZ2.Metas
{
    public class OptionCategoryMeta
    {
        public string ID { get; private set; }
        public string Label { get; private set; } = string.Empty;

        public OptionCategoryMeta(string iD)
        {
            ID = iD;
        }
        public static OptionCategoryMeta? FromXmlNode(XmlNode node, string defaultNsp)
        {
            var id = node.GetAttribute("id");
            if (string.IsNullOrEmpty(id))
            {
                Log.LogError($"The {nameof(id)} of a {nameof(OptionCategoryMeta)} is invalid.");
                return null;
            }
            var label = node.GetAttribute("label") ?? string.Empty;
            return new OptionCategoryMeta(id)
            {
                Label = label,
            };
        }
    }
}
